    /**
     * @param Doctrine_Connection|null $conn
     * @return bool|void
     */
    public function delete(Doctrine_Connection $conn = null) {
        if ($this->Type == 'product-photo') {
            foreach (self::getSizes() as $folder) {
                deleteFile(self::TYPE_PRODUCT_PHOTO_FOLDER . $folder . '/' . $this->Name . '.' . $this->Extension);
            }
        }

        if ($this->Type == self::TYPE_FEEDBACK_ATTACHMENT) {
            deleteFile(self::TYPE_FEEDBACK_ATTACHMENT_FOLDER . $this->getFileName());
        }

       return parent::delete($conn);
    }

