        return $sizes;
    }

    /**
     * @param int $ID
     * @param int $size
     * @return string
     */
    public static function getFileUrlByID(int $ID, int $size): string {
        $file = self::getFile($ID);

        return _bu() . '/files/images/' . $size . '/' . $file->Name . '.' . $file->Extension;
    }

    /**
