     */
    public static function getFileUrl(array|Admin_Model_ProductImage|Admin_Model_News $file, string $folder, string $fileKey): string {
        return  _bu() . '/files/images/' . $folder . '/' . $file[$fileKey]["Name"] . '.' . $file[$fileKey]["Extension"];
    }

    /**
     * @param string $type
     * @param string $fileName
     * @param string $extension
     * @return Common_Model_File
     */
    public static function createFile(string $type, string $fileName, string $extension): Common_Model_File {
        $file = new Common_Model_File();
        $file->Type = $type;
        $file->Name = $fileName;
        $file->Extension = $extension;
        $file->save();

        return $file;
    }

    /**
     * @param $ID
     * @return self
     */
    public static function getFile($ID): Common_Model_File {
        $query = Doctrine_Query::create();
        $query->from('Common_Model_File object');
        $query->where('object.ID = ?', $ID);

        /** @var  \Common_Model_File $file */
        return $query->fetchOne();
    }
